if (session_status() === PHP_SESSION_NONE) session_start();
include "../../inc/config.php";
session_check_json();
function la_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');$p=array('status'=>$s);if($m!=='')$p[$s==='good'?'message':'error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function la_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function la_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;}
function la_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;}
function la_c($v){return strtoupper(trim((string)$v));}
function la_user(){return isset($_SESSION['username'])&&$_SESSION['username']!==''?$_SESSION['username']:'admin';}
function la_select2($rows,$id,$cb){$out=array();foreach($rows as $r)$out[]=array('id'=>$r->$id,'text'=>$cb($r));header('Content-Type: application/json; charset=utf-8');echo json_encode(array('results'=>$out));exit;}
function la_no(){global $db;$prefix='LVA'.date('Ym');$r=$db->fetch("SELECT approval_no FROM erp_leave_approval WHERE approval_no LIKE ? ORDER BY approval_no DESC LIMIT 1",array($prefix.'%'));$n=$r?((int)substr($r->approval_no,-4)+1):1;return $prefix.sprintf('%04d',$n);}
function la_request_row($id){global $db;return $db->fetch("SELECT l.*,e.employee_no,e.full_name,d.nm_dept,j.job_title_code,j.job_title_name,a.employee_no approver_no,a.full_name approver_name,hr.employee_no hr_no,hr.full_name hr_name FROM erp_leave_request l JOIN erp_employee_master e ON e.id=l.employee_id LEFT JOIN dept d ON d.kd_dept=l.department_code LEFT JOIN erp_job_title j ON j.id=l.job_title_id LEFT JOIN erp_employee_master a ON a.id=l.approver_employee_id LEFT JOIN erp_employee_master hr ON hr.id=l.hr_reviewer_employee_id WHERE l.id=? LIMIT 1",array((int)$id));}
$act=isset($_GET['act'])?$_GET['act']:'';$username=la_user();
switch($act){
  case 'employee_search':
    $term=trim(la_p('term'));$like='%'.$term.'%';$rows=$db->query("SELECT id,employee_no,full_name FROM erp_employee_master WHERE employment_status IN ('ACTIVE','PROBATION','CONTRACT') AND (?='' OR employee_no LIKE ? OR full_name LIKE ?) ORDER BY employee_no LIMIT 30",array($term,$like,$like));la_select2($rows,'id',function($r){return $r->employee_no.' - '.$r->full_name;});break;
  case 'department_search':
    $term=trim(la_p('term'));$like='%'.$term.'%';$rows=$db->query("SELECT kd_dept,nm_dept,dept_type FROM dept WHERE status='ACTIVE' AND (?='' OR kd_dept LIKE ? OR nm_dept LIKE ?) ORDER BY kd_dept LIMIT 30",array($term,$like,$like));la_select2($rows,'kd_dept',function($r){return $r->kd_dept.' - '.$r->nm_dept.' ['.$r->dept_type.']';});break;
  case 'request_search':
    $term=trim(la_p('term'));$like='%'.$term.'%';$rows=$db->query("SELECT l.id,l.leave_no,e.employee_no,e.full_name,l.workflow_status,l.start_date,l.end_date FROM erp_leave_request l JOIN erp_employee_master e ON e.id=l.employee_id WHERE l.workflow_status IN ('SUBMITTED','MANAGER_APPROVED','HR_APPROVED','RETURNED') AND (?='' OR l.leave_no LIKE ? OR e.employee_no LIKE ? OR e.full_name LIKE ?) ORDER BY l.request_date DESC LIMIT 30",array($term,$like,$like,$like));la_select2($rows,'id',function($r){return $r->leave_no.' - '.$r->employee_no.' '.$r->full_name.' ['.$r->workflow_status.']';});break;
  case 'get':
    $r=$db->fetch("SELECT * FROM erp_leave_approval WHERE id=? LIMIT 1",array((int)la_p('id')));if(!$r)la_json('error','Approval log tidak ditemukan.');$req=la_request_row($r->leave_request_id);$d=(array)$r;$d['leave_request_text']=$req?$req->leave_no.' - '.$req->employee_no.' '.$req->full_name:'';la_json('good','',array('data'=>$d));break;
  case 'decision':
    $id=(int)la_p('leave_request_id');$decision=la_c(la_p('decision'));$step=la_c(la_p('approval_step','MANAGER'));$note=trim(la_p('approval_note'));$approver=la_p('approver_employee_id')!==''?(int)la_p('approver_employee_id'):null;
    $req=la_request_row($id);if(!$req)la_json('error','Leave Request tidak ditemukan.');if(!in_array($decision,array('APPROVE','REJECT','RETURN','CANCEL'),true))la_json('error','Decision tidak valid.');if(!in_array($step,array('MANAGER','HR','FINAL'),true))la_json('error','Approval step tidak valid.');
    if($req->workflow_status==='APPROVED'&&$decision!=='CANCEL')la_json('error','Leave sudah approved.');
    $newStatus=$decision==='APPROVE'?($step==='MANAGER'?'MANAGER_APPROVED':($step==='HR'?'HR_APPROVED':'APPROVED')):($decision==='REJECT'?'REJECTED':($decision==='RETURN'?'RETURNED':'CANCELLED'));
    $dec=$decision==='APPROVE'?'APPROVED':($decision==='REJECT'?'REJECTED':($decision==='RETURN'?'RETURNED':'CANCELLED'));
    $no=la_no();$data=array('approval_no'=>$no,'leave_request_id'=>$id,'approval_step'=>$step,'approver_employee_id'=>$approver?:$req->approver_employee_id,'decision'=>$dec,'decision_date'=>date('Y-m-d H:i:s'),'approval_note'=>$note,'previous_status'=>$req->workflow_status,'new_status'=>$newStatus,'created_by'=>$username,'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s'));
    $ok=$db->insert('erp_leave_approval',$data);if(!$ok)la_json('error',$db->getErrorMessage()?:'Approval gagal disimpan.');
    $db->update('erp_leave_request',array('workflow_status'=>$newStatus,'approval_level'=>$newStatus==='MANAGER_APPROVED'?'HR':'FINAL','decision'=>$dec,'decision_by'=>$username,'decision_at'=>date('Y-m-d H:i:s'),'approver_note'=>$note,'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s')),'id',$id);
    if(function_exists('simpan_log'))simpan_log('User '.$username.' '.$dec.' Leave Request '.$req->leave_no.' pada '.date('Y-m-d H:i:s'),$username);
    la_json('good','Leave approval berhasil diproses.',array('approval_no'=>$no));
  case 'detail':
    $req=la_request_row((int)la_p('id'));if(!$req){echo '<div class="alert alert-warning">Leave Request tidak ditemukan.</div>';break;}$logs=$db->query("SELECT a.*,e.employee_no,e.full_name FROM erp_leave_approval a LEFT JOIN erp_employee_master e ON e.id=a.approver_employee_id WHERE a.leave_request_id=? ORDER BY a.id DESC",array($req->id));echo '<h3 style="margin-top:0">'.la_h($req->leave_no).' <small>'.la_h($req->employee_no.' - '.$req->full_name).'</small></h3><span class="label label-info">'.la_h($req->leave_type).'</span> <span class="label label-success">'.la_h($req->workflow_status).'</span><hr>';echo '<div class="row"><div class="col-sm-3"><b>'.hr_h('hr_period', 'Period').'</b><br>'.la_h($req->start_date.' s/d '.$req->end_date).'</div><div class="col-sm-3"><b>Days</b><br>'.la_h($req->total_days).'</div><div class="col-sm-3"><b>'.hr_h('hr_department', 'Department').'</b><br>'.la_h($req->department_code.' - '.$req->nm_dept).'</div><div class="col-sm-3"><b>Approver</b><br>'.la_h($req->approver_no.' - '.$req->approver_name).'</div></div><hr><b>Reason</b><p>'.nl2br(la_h($req->reason?:'-')).'</p><h4>Approval History</h4><table class="table table-bordered"><tr><th>'.hr_h('common_no', 'No').'</th><th>Step</th><th>Decision</th><th>'.hr_h('common_status', 'Status').'</th><th>Approver</th><th>'.hr_h('hr_date', 'Date').'</th><th>Note</th></tr>';$n=1;foreach($logs as $l){echo '<tr><td>'.$n++.'</td><td>'.la_h($l->approval_step).'</td><td>'.la_h($l->decision).'</td><td>'.la_h($l->previous_status.' -> '.$l->new_status).'</td><td>'.la_h($l->employee_no.' '.$l->full_name).'</td><td>'.la_h($l->decision_date).'</td><td>'.la_h($l->approval_note).'</td></tr>';}echo '</table>';break;
  case 'export':
    $initial=ob_get_level();ob_start();error_reporting(E_ALL & ~E_NOTICE & ~E_WARNING & ~E_DEPRECATED & ~E_USER_DEPRECATED);require_once "../../inc/lib/PHPExcel.php";require_once "../../inc/excel_style_helper.php";PHPExcel_Shared_File::setUseUploadTempDirectory(true);$from=la_g('tgl_awal',date('Y-01-01'));$to=la_g('tgl_akhir',date('Y-m-d'));$status=la_c(la_g('status'));$dept=la_c(la_g('department_code'));$kw=trim(la_g('keyword'));$w=" WHERE l.start_date<=? AND l.end_date>=? ";$p=array($to,$from);if($status!==''){$w.=" AND l.workflow_status=? ";$p[]=$status;}if($dept!==''){$w.=" AND l.department_code=? ";$p[]=$dept;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (l.leave_no LIKE ? OR e.employee_no LIKE ? OR e.full_name LIKE ?) ";array_push($p,$like,$like,$like);}$rows=$db->query("SELECT l.*,e.employee_no,e.full_name,d.nm_dept,a.approval_no,a.approval_step,a.decision approval_decision,a.decision_date,a.approval_note FROM erp_leave_request l JOIN erp_employee_master e ON e.id=l.employee_id LEFT JOIN dept d ON d.kd_dept=l.department_code LEFT JOIN erp_leave_approval a ON a.leave_request_id=l.id $w ORDER BY l.start_date DESC,l.id DESC,a.id DESC",$p);$excel=new PHPExcel();$sheet=$excel->setActiveSheetIndex(0);$sheet->setTitle(erp_export_sheet_title('Leave Approval'));$heads=array(erp_export_label("No"),erp_export_label("Leave No"),erp_export_label("Employee"),erp_export_label("Department"),erp_export_label("Type"),erp_export_label("Period"),erp_export_label("Days"),erp_export_label("Request Status"),erp_export_label("Approval No"),erp_export_label("Step"),erp_export_label("Decision"),erp_export_label("Decision Date"),erp_export_label("Note"),erp_export_label("Updated By"));foreach($heads as $i=>$h)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).'4',$h);$rnum=5;$n=1;foreach($rows as $r){$vals=array($n++,$r->leave_no,$r->employee_no.' - '.$r->full_name,$r->department_code.' - '.$r->nm_dept,$r->leave_type,$r->start_date.' s/d '.$r->end_date,(float)$r->total_days,$r->workflow_status,$r->approval_no,$r->approval_step,$r->approval_decision,$r->decision_date,$r->approval_note,$r->updated_by?:$r->created_by);foreach($vals as $i=>$v)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).$rnum,$v);$rnum++;}erpkb_excel_apply_standard_style($excel,array('sheet'=>$sheet,'title'=>erp_export_title('LEAVE APPROVAL REPORT'),'header_row'=>4,'first_data_row'=>5,'last_data_row'=>max(5,$rnum-1),'column_count'=>count($heads),'decimal_columns'=>array('G'),'filters'=>array('Periode'=>$from.' s/d '.$to,'Status'=>$status?:erp_export_all_text(),'Department'=>$dept?:erp_export_all_text())));$tmp=erpkb_excel_temp_file('leave_approval_');PHPExcel_IOFactory::createWriter($excel,'Excel2007')->save($tmp);$size=@filesize($tmp);$sig=@file_get_contents($tmp,false,null,0,2);if(!$size||$sig!=='PK'){@unlink($tmp);while(ob_get_level()>$initial)ob_end_clean();echo erp_t('export_excel_invalid_file','File Excel gagal dibuat dengan benar.');exit;}while(ob_get_level()>$initial)ob_end_clean();header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment; filename="leave_approval_'.date('Ymd_His').'.xlsx"');header('Content-Length: '.$size);header('Cache-Control: max-age=0');header('Pragma: public');readfile($tmp);@unlink($tmp);exit;
  default:la_json('error','Action tidak dikenal.');
}
